// EDTMRS - Endpoints Page
import React, { useState, useEffect, useCallback } from 'react';
import { endpointsAPI } from '../utils/api';

function StatusBadge({ status, isolated }) {
  if (isolated) return (
    <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-red-600/20 text-red-300 border border-red-600/40">
      <span className="w-1.5 h-1.5 rounded-full bg-red-400" /> ISOLATED
    </span>
  );
  if (status === 'online') return (
    <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-emerald-500/20 text-emerald-400 border border-emerald-500/40">
      <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" /> ONLINE
    </span>
  );
  return (
    <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-gray-500/20 text-gray-400 border border-gray-500/40">
      <span className="w-1.5 h-1.5 rounded-full bg-gray-500" /> OFFLINE
    </span>
  );
}

export default function EndpointsPage({ liveEvents }) {
  const [endpoints, setEndpoints] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [toast, setToast]         = useState('');

  const fetchEndpoints = useCallback(async () => {
    try {
      const res = await endpointsAPI.list();
      setEndpoints(res.data.endpoints);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchEndpoints(); }, [fetchEndpoints]);
  useEffect(() => { if (liveEvents?.length) fetchEndpoints(); }, [liveEvents, fetchEndpoints]);

  const handleIsolate = async (ep) => {
    const reason = window.prompt(`Reason for isolating ${ep.hostname}?`, 'Suspicious activity');
    if (reason === null) return;
    try {
      await endpointsAPI.isolate(ep.id, reason);
      setToast(`${ep.hostname} isolated`);
      setTimeout(() => setToast(''), 3000);
      fetchEndpoints();
    } catch {}
  };

  const handleUnisolate = async (ep) => {
    try {
      await endpointsAPI.unisolate(ep.id);
      setToast(`${ep.hostname} unisolated`);
      setTimeout(() => setToast(''), 3000);
      fetchEndpoints();
    } catch {}
  };

  const online  = endpoints.filter((e) => e.status === 'online' && !e.is_isolated).length;
  const offline = endpoints.filter((e) => e.status !== 'online').length;
  const isolated = endpoints.filter((e) => e.is_isolated).length;

  return (
    <div className="space-y-5">
      {toast && (
        <div className="fixed top-5 right-5 z-50 px-4 py-3 bg-blue-600/20 border border-blue-500/40 text-blue-400 rounded-xl text-sm shadow-xl">
          ✓ {toast}
        </div>
      )}

      <div>
        <h1 className="text-xl font-bold text-white">Endpoints</h1>
        <p className="text-gray-500 text-sm mt-0.5">User PCs running the EDTMRS agent</p>
      </div>

      {/* Summary */}
      <div className="grid grid-cols-3 gap-4">
        {[
          { label: 'Online', value: online,   color: 'emerald', icon: '◉' },
          { label: 'Offline', value: offline,  color: 'gray',    icon: '◎' },
          { label: 'Isolated', value: isolated, color: 'red',     icon: '⊗' },
        ].map((s) => (
          <div key={s.label} className={`bg-[#0f1629] border border-[#1e2d4d] rounded-xl p-4`}>
            <div className="text-2xl font-bold text-white mb-1">{s.value}</div>
            <div className="text-gray-500 text-sm">{s.icon} {s.label}</div>
          </div>
        ))}
      </div>

      {/* Table */}
      <div className="bg-[#0f1629] border border-[#1e2d4d] rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-[#1e2d4d] text-gray-500 text-xs uppercase tracking-wider">
                <th className="px-5 py-3 text-left">Hostname</th>
                <th className="px-5 py-3 text-left">IP Address</th>
                <th className="px-5 py-3 text-left">User</th>
                <th className="px-5 py-3 text-left">Agent</th>
                <th className="px-5 py-3 text-left">Status</th>
                <th className="px-5 py-3 text-left">Last Seen</th>
                <th className="px-5 py-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={7} className="text-center py-16">
                  <div className="flex justify-center"><div className="w-6 h-6 border-2 border-blue-500/30 border-t-blue-400 rounded-full animate-spin" /></div>
                </td></tr>
              ) : !endpoints.length ? (
                <tr><td colSpan={7} className="text-center py-16 text-gray-600">
                  <div className="text-2xl mb-2">◈</div>
                  <div>No endpoints registered yet. Start the agent on a User PC.</div>
                </td></tr>
              ) : endpoints.map((ep) => (
                <tr key={ep.id} className="border-b border-[#1a2035] hover:bg-white/2 transition-colors">
                  <td className="px-5 py-3">
                    <div className="text-white font-semibold">{ep.hostname}</div>
                    <div className="text-gray-600 text-xs">{ep.os_info || 'Windows'}</div>
                  </td>
                  <td className="px-5 py-3 font-mono text-gray-300 text-xs">{ep.ip_address || '—'}</td>
                  <td className="px-5 py-3 text-gray-400 text-xs">{ep.username || '—'}</td>
                  <td className="px-5 py-3 text-gray-500 text-xs font-mono">v{ep.agent_version}</td>
                  <td className="px-5 py-3">
                    <StatusBadge status={ep.status} isolated={!!ep.is_isolated} />
                  </td>
                  <td className="px-5 py-3 text-gray-500 text-xs whitespace-nowrap">
                    {ep.last_seen ? new Date(ep.last_seen).toLocaleString() : 'Never'}
                  </td>
                  <td className="px-5 py-3">
                    {ep.is_isolated ? (
                      <button onClick={() => handleUnisolate(ep)}
                        className="px-3 py-1 bg-emerald-600/20 hover:bg-emerald-600/30 border border-emerald-500/40 text-emerald-400 rounded-lg text-xs transition-all">
                        ↺ Unisolate
                      </button>
                    ) : (
                      <button onClick={() => handleIsolate(ep)}
                        className="px-3 py-1 bg-red-600/20 hover:bg-red-600/30 border border-red-500/40 text-red-400 rounded-lg text-xs transition-all">
                        ⊗ Isolate
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
